// Merge Shopify order with today's exchange rate
const order = $('Shopify: Order Created').first().json;
const rateRow = $input.first().json || {};
const rate = rateRow.Bs != null ? parseFloat(rateRow.Bs) : null;

const financial = (order.financial_status || '').toLowerCase();
let status = 'pendiente_pago';
if (['paid','authorized','pending'].includes(financial)) status = 'confirmado';
if ((order.fulfillment_status || '').toLowerCase() === 'fulfilled') status = 'entregado';
if (['refunded','voided'].includes(financial)) status = 'cancelado';

const cust = order.customer || {};
const ship = order.shipping_address || order.billing_address || {};
const clientName = [cust.first_name, cust.last_name].filter(Boolean).join(' ').trim() || ship.name || null;
const clientPhone = (cust.phone || ship.phone || order.phone || '').replace(/\s+/g,'') || null;
const addressParts = [ship.address1, ship.address2, ship.city, ship.province].filter(Boolean);
const deliveryAddress = addressParts.length ? addressParts.join(', ') : null;

const subtotalUsd = parseFloat(order.subtotal_price || order.current_subtotal_price || 0);
const totalUsd = parseFloat(order.total_price || order.current_total_price || 0);
const deliveryCostUsd = parseFloat((order.total_shipping_price_set && order.total_shipping_price_set.shop_money && order.total_shipping_price_set.shop_money.amount) || order.shipping_lines?.[0]?.price || 0);
const totalBs = rate ? Math.round(totalUsd * rate * 100) / 100 : null;

let paymentMethod = null;
const gw = (order.payment_gateway_names || order.gateway || []).toString().toLowerCase();
if (gw.includes('zelle')) paymentMethod = 'zelle';
else if (gw.includes('cash') || gw.includes('manual')) paymentMethod = 'cash';
else if (gw.includes('binance')) paymentMethod = 'binance';
else if (gw) paymentMethod = 'bolivares';

const orderPayload = {
  shopify_order_id: String(order.id),
  order_number: String(order.order_number || order.name || ''),
  client_name: clientName,
  client_phone: clientPhone,
  client_city: ship.city || null,
  channel: 'shopify',
  status,
  delivery_type: deliveryAddress ? 'delivery' : null,
  delivery_address: deliveryAddress,
  subtotal_usd: subtotalUsd || null,
  delivery_cost_usd: deliveryCostUsd || 0,
  total_usd: totalUsd || null,
  total_bs: totalBs,
  exchange_rate: rate,
  payment_method: paymentMethod,
  notes: order.note || null
};

const lineItems = (order.line_items || []).map(li => ({
  sku: li.sku || null,
  product_name: li.title || li.name || 'Producto',
  size: (li.variant_title || '').split('/')[0]?.trim() || null,
  color: (li.variant_title || '').split('/')[1]?.trim() || null,
  quantity: li.quantity || 1,
  unit_price_usd: parseFloat(li.price || 0),
  total_price_usd: Math.round(parseFloat(li.price || 0) * (li.quantity || 1) * 100) / 100
}));

return [{ json: { order: orderPayload, lineItems, _meta: { orderNumber: orderPayload.order_number, totalUsd, totalBs, rate } } }];

// Attach order_id to each line item
const inserted = $input.first().json;
const orderRow = Array.isArray(inserted) ? inserted[0] : inserted;
const orderId = orderRow.id;
const lineItems = $('Transform order').first().json.lineItems || [];
const rows = lineItems.map(li => ({ ...li, order_id: orderId }));
const meta = $('Transform order').first().json._meta;
return [{ json: { rows, orderId, orderRow, _meta: meta } }];

